// Build a structured editorial review prompt.
const input = $input.first().json;
const body = input.body ?? input;

if (!body.article?.markdown || !body.article?.title) {
  throw new Error('article.title and article.markdown are required');
}

const systemPrompt = `你是 Phoenix AI Content Engine 的資深編輯與事實風險審查員。你的工作不是重寫整篇文章，而是：
1. 檢查結構、論證、可讀性與 Medium 閱讀體驗。
2. 檢查是否存在無來源的具體數字、日期、人物說法或直接引用。
3. 檢查是否過度重複、過度口號化、AI 腔或空泛。
4. 檢查文風是否與 styleContext 一致，但不得要求複製原句。
5. 當文章可接受時，保留原文，只做必要修訂。
6. 僅輸出合法 JSON，不要使用 Markdown code fence。

輸出格式：
{
  "score": 0,
  "approved": false,
  "issues": [
    {
      "type": "structure|fact_risk|style|clarity|duplication|seo",
      "severity": "low|medium|high",
      "message": "問題說明"
    }
  ],
  "revisionNotes": ["修訂說明"],
  "revisedTitle": "修訂後標題",
  "revisedSubtitle": "修訂後副標題",
  "revisedSummary": "修訂後摘要",
  "revisedTags": ["標籤"],
  "revisedMarkdown": "# 修訂後完整文章"
}

評分標準：
- 結構與論證 25
- 可讀性與節奏 20
- 事實風險控制 20
- 文風一致性 15
- 實用性與具體性 10
- 標題摘要與 SEO 10

approved 僅在 score >= 85 且不存在 high severity issue 時為 true。`;

const userPrompt = JSON.stringify({
  originalContent: {
    title: body.title,
    url: body.url,
    content: body.content
  },
  analysis: body.analysis,
  research: body.research,
  styleContext: body.styleRag,
  article: body.article
});

return [{
  json: {
    original: body,
    systemPrompt,
    userPrompt
  }
}];

