// Parse and validate the primary review response.
const response = $input.first().json;
const original = $('BuildReviewerPrompt').first().json.original;
const statusCode = response.statusCode ?? 0;
const raw = response.body?.choices?.[0]?.message?.content ?? '';

let review = null;
let parseError = null;

try {
  review = JSON.parse(String(raw).replace(/^```json\s*|\s*```$/g, '').trim());
} catch (error) {
  parseError = error.message;
}

const valid = statusCode >= 200 &&
  statusCode < 300 &&
  review &&
  Number.isFinite(Number(review.score)) &&
  typeof review.approved === 'boolean';

return [{
  json: {
    original,
    provider: 'openrouter',
    statusCode,
    raw,
    review,
    valid,
    fallbackRequired: !valid,
    error: parseError
  }
}];

