// Parse the NVIDIA fallback review.
// NVIDIA may return a valid review without a fully revised article.
// Missing revised fields are allowed and will fall back to the original draft.
const response = $input.first().json;
const original = $('BuildReviewerPrompt').first().json.original;
const statusCode = response.statusCode ?? 0;
const raw = response.body?.choices?.[0]?.message?.content ?? '';

let review;
try {
  review = JSON.parse(String(raw).replace(/^```json\s*|\s*```$/g, '').trim());
} catch (error) {
  throw new Error(`NVIDIA reviewer response is not valid JSON: ${error.message}`);
}

if (!(statusCode >= 200 && statusCode < 300)) {
  throw new Error(`NVIDIA reviewer request failed with status ${statusCode}`);
}

if (
  !Number.isFinite(Number(review.score)) ||
  typeof review.approved !== 'boolean'
) {
  throw new Error('NVIDIA reviewer response is missing score or approved');
}

return [{
  json: {
    original,
    provider: 'nvidia',
    review
  }
}];

// Merge the selected review into the article contract.
const input = $input.first().json;
const original = input.original;
const review = input.review ?? {};
const issues = Array.isArray(review.issues) ? review.issues : [];
const score = Math.max(0, Math.min(100, Number(review.score ?? 0)));
const hasHighSeverity = issues.some((issue) => String(issue.severity).toLowerCase() === 'high');
const approved = score >= 85 && review.approved === true && !hasHighSeverity;

const revisedTitle = typeof review.revisedTitle === 'string' && review.revisedTitle.trim()
  ? review.revisedTitle.trim()
  : original.article.title;

const revisedSubtitle = typeof review.revisedSubtitle === 'string'
  ? review.revisedSubtitle.trim()
  : (original.article.subtitle ?? '');

const revisedSummary = typeof review.revisedSummary === 'string'
  ? review.revisedSummary.trim()
  : (original.article.summary ?? '');

const revisedTags = Array.isArray(review.revisedTags) && review.revisedTags.length
  ? review.revisedTags.map((tag) => String(tag).trim()).filter(Boolean).slice(0, 5)
  : (original.article.tags ?? []);

const revisedMarkdown = typeof review.revisedMarkdown === 'string' && review.revisedMarkdown.trim().length >= 100
  ? review.revisedMarkdown.trim()
  : original.article.markdown;

return [{
  json: {
    ...original,
    article: {
      ...original.article,
      title: revisedTitle,
      subtitle: revisedSubtitle,
      summary: revisedSummary,
      tags: revisedTags,
      markdown: revisedMarkdown
    },
    review: {
      score,
      approved,
      issues,
      revisionNotes: Array.isArray(review.revisionNotes) ? review.revisionNotes : [],
      revisedContentApplied: revisedMarkdown !== original.article.markdown
    },
    metadata: {
      ...original.metadata,
      reviewer: '07-reviewer-agent',
      reviewerVersion: '0.7.1',
      reviewerProvider: input.provider,
      status: approved ? 'approved' : 'needs_revision',
      reviewedAt: new Date().toISOString()
    }
  }
}];
